#!/usr/bin/env python3
"""DGX DEPLOY v19.34.242 — fix backfill JOB 2: query alert_outcomes by closed_at
(was created_at -> scanned=0). Script-only change; NO service restart needed.
Idempotent: rewrites the backfill, git commit && git push.
Run on repo root: .venv/bin/python /tmp/deploy_v19_34_242.py"""
import base64, gzip, os, subprocess, sys
REPO=os.getcwd()
REL='backend/scripts/backfill_v19_34_240_hygiene.py'
B=''
def main():
    if not os.path.isdir(os.path.join(REPO,"backend","scripts")):
        print("[FATAL] not repo root"); sys.exit(1)
    dst=os.path.join(REPO,REL)
    open(dst,"wb").write(gzip.decompress(base64.b64decode(B)))
    print(f"[WROTE] {REL}")
    subprocess.run(["git","add",REL],cwd=REPO)
    c=subprocess.run(["git","commit","-m","v19.34.242 — fix hygiene backfill: alert_outcomes keyed on closed_at"],cwd=REPO)
    if c.returncode!=0: print("[INFO] commit no-op")
    p=subprocess.run(["git","push"],cwd=REPO)
    if p.returncode!=0: print("[WARN] push failed — commit is local")
    print("[DONE] v19.34.242. Re-run the backfill --dry-run; alert_outcomes scanned should be >0.")
if __name__=="__main__": main()
